SELECT method_name, description
FROM sampling_methods
WHERE method_id = 0;

SELECT COUNT(DISTINCT sample_id) AS sample_count
FROM samples
WHERE location = 'Forest';

SELECT AVG(dm.brillouin_diversity) AS overall_avg_brillouin_diversity
FROM access_logs al
JOIN diversity_metrics dm ON al.sample_id = dm.sample_id;

SELECT DISTINCT collection_date
FROM samples
ORDER BY collection_date DESC;

SELECT brillouin_diversity
FROM diversity_metrics
WHERE sample_id = 0;
